// Texture-based Fractal Brownian Motion (FBM)
float TexFBM(float2 uv, sampler2D noiseTexture, int octaves, float persistence) {
    float total = 0.0;
    float amplitude = 1.0;
    float frequency = 1.0;

    for (int i = 0; i < octaves; i++) {
        total += texture(noiseTexture, uv * frequency).r * amplitude;
        frequency *= 2.0; // Increase frequency for the next octave
        amplitude *= persistence; // Decrease amplitude based on persistence
    }

    return total;
}

