float Noise2D(float2 uv) {
    float2 i = floor(uv);
    float2 f = frac(uv);

    // Get random gradients for each corner (unit vectors)
    float2 g00 = normalize(Hash22(i + float2(0.0, 0.0)) - 0.5);
    float2 g10 = normalize(Hash22(i + float2(1.0, 0.0)) - 0.5);
    float2 g01 = normalize(Hash22(i + float2(0.0, 1.0)) - 0.5);
    float2 g11 = normalize(Hash22(i + float2(1.0, 1.0)) - 0.5);

    // Dot products
    float d00 = dot(g00, f - float2(0.0, 0.0));
    float d10 = dot(g10, f - float2(1.0, 0.0));
    float d01 = dot(g01, f - float2(0.0, 1.0));
    float d11 = dot(g11, f - float2(1.0, 1.0));

    // Fade curve (smooth interpolation)
    float2 u = f * f * f * (f * (f * 6.0 - 15.0) + 10.0);

    // Bilinear interpolation
    return lerp(lerp(d00, d10, u.x), lerp(d01, d11, u.x), u.y);
}

