float Noise3D(float3 uv) {
    float3 i = floor(uv);
    float3 f = fract(uv);

    // Get random gradients for each corner (unit vectors)
    float3 g000 = normalize(Hash33(i + float3(0.0, 0.0, 0.0)) - 0.5);
    float3 g100 = normalize(Hash33(i + float3(1.0, 0.0, 0.0)) - 0.5);
    float3 g010 = normalize(Hash33(i + float3(0.0, 1.0, 0.0)) - 0.5);
    float3 g110 = normalize(Hash33(i + float3(1.0, 1.0, 0.0)) - 0.5);
    float3 g001 = normalize(Hash33(i + float3(0.0, 0.0, 1.0)) - 0.5);
    float3 g101 = normalize(Hash33(i + float3(1.0, 0.0, 1.0)) - 0.5);
    float3 g011 = normalize(Hash33(i + float3(0.0, 1.0, 1.0)) - 0.5);
    float3 g111 = normalize(Hash33(i + float3(1.0, 1.0, 1.0)) - 0.5);

    // Dot products
    float d000 = dot(g000, f - float3(0.0, 0.0, 0.0));
    float d100 = dot(g100, f - float3(1.0, 0.0, 0.0));
    float d010 = dot(g010, f - float3(0.0, 1.0, 0.0));
    float d110 = dot(g110, f - float3(1.0, 1.0, 0.0));
    float d001 = dot(g001, f - float3(0.0, 0.0, 1.0));
    float d101 = dot(g101, f - float3(1.0, 0.0, 1.0));
    float d011 = dot(g011, f - float3(0.0, 1.0, 1.0));
    float d111 = dot(g111, f - float3(1.0, 1.0, 1.0));

    // Fade curve (smooth interpolation)
    float3 u = f * f * f * (f * (f * 6.0 - 15.0) + 10.0);

    // Trilinear interpolation
    float x00 = lerp(d000, d100, u.x);
    float x10 = lerp(d010, d110, u.x);
    float x01 = lerp(d001, d101, u.x);
    float x11 = lerp(d011, d111, u.x);

    float y0 = lerp(x00, x10, u.y);
    float y1 = lerp(x01, x11, u.y);

    return lerp(y0, y1, u.z);
}

